#include <bits/stdc++.h>
using namespace std;
struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(NULL) {}
};
int main() {
    int n;
    cin >> n;
    ListNode *head = NULL;
    ListNode *curr = NULL;
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        if (!head) {
            head = new ListNode(val);
            curr = head;
        } else {
            curr->next = new ListNode(val);
            curr = curr->next;
        }
    }
    ListNode *prev = NULL;
    curr = head;
    while (curr) {
        ListNode *next_node = curr->next;
        curr->next = prev;
        prev = curr;
        curr = next_node;
    }
    head = prev;
    vector<int> result;
    curr = head;
    while (curr) {
        result.push_back(curr->val);
        curr = curr->next;
    }
    cout << result.size() << endl;
    for (int val : result) {
        cout << val << endl;
    }
    cout << 0 << endl;
}
